  "darlington-cover": {
    "title": "Darlington cover",
    "year": 2011,
    "categories": ["graphic", "bmr"],
    "media": [{
      "type": "bandcamp",
      "bandcamp-type": "album",
      "id": 3744730925
    }],
    "tagline": "Cover Art",
    "slug": "darlington-cover",
    "body": "Having not released any music in a while, Judd and I decided to knock down their creative wall by challenging ourselves to fully create a mixtape in under an hour. This is that mixtape. Everything from writing to beatmaking to the album cover was done within a 1-hour span.\n\nMixtape by Creation. 4 freestyles: 3 over tracks by Cupp Cave, and one over a Christopher Knollmeyer edit of Steppin' Out by Joe Jackson. Engineered by clown.\n"
  },
